// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

import "./LendingPoolUpgradeable.sol";

contract ReentrancyAttacker {
    LendingPoolUpgradeable public target;

    constructor(address _target) {
        target = LendingPoolUpgradeable(payable(_target));
    }

    // Trigger the attack
    function attack() external payable {
        target.deposit{value: msg.value}();
        // This will fail because our pool uses ReentrancyGuardUpgradeable
        target.borrow(msg.value); 
    }

    // Fallback function for the attack loop
    receive() external payable {
        if (address(target).balance >= 1 ether) {
            target.borrow(1 ether);
        }
    }
}
